const resp = $input.first().json;
const stdout = resp.stdout || '';
const ok = resp.ok === true;
const exitCode = resp.exit_code ?? -1;
const duracion = resp.duracion_s ? `${Math.floor(resp.duracion_s/60)}m ${resp.duracion_s%60}s` : 'N/D';

// Extract totals from pipeline output
const empresasMatch = stdout.match(/TOTAL\s+(\d+)\s+businesses/);
const leadsMatch    = stdout.match(/Qualified leads\s*:\s*(\d+)/);
const emailsMatch   = stdout.match(/Emails generated\s*:\s*(\d+)/);
const pvgisMatch    = stdout.match(/with PVGIS\s*:\s*(\d+)/);
const pdfsMatch     = stdout.match(/PDFs generated\s*:\s*(\d+)/);

const empresas = empresasMatch ? empresasMatch[1] : '?';
const leads    = leadsMatch    ? leadsMatch[1]    : '?';
const emails   = emailsMatch   ? emailsMatch[1]   : '?';
const pvgis    = pvgisMatch    ? pvgisMatch[1]    : '?';
const pdfs     = pdfsMatch     ? pdfsMatch[1]     : '?';

const fecha = new Date().toLocaleString('es-ES', {timeZone: 'Europe/Madrid'});

const message = ok
  ? `🌞 <b>Pipeline nocturno completado</b>\n` +
    `📅 ${fecha}\n\n` +
    `📊 <b>Resultados:</b>\n` +
    `  🔍 Companies scraped: ${empresas}\n` +
    `  ⭐ Qualified leads: ${leads}\n` +
    `  ✉️ Emails generated: ${emails}\n` +
    `  ☀️ PVGIS analysis: ${pvgis}\n` +
    `  📄 PDFs creados: ${pdfs}\n` +
    `  ⏱ Tiempo total: ${duracion}\n\n` +
    `✅ Sistema listo para envío de emails.`
  : `❌ <b>Pipeline nocturno FALLÓ</b>\n` +
    `📅 ${fecha} | Exit code: ${exitCode}\n\n` +
    `<pre>${(resp.stderr || stdout).slice(-500)}</pre>`;

return [{ json: { message, ok, empresas, leads, emails, pdfs, duracion } }];
